int main(void){MockArray*a=calloc(1,sizeof(*a));TurboJSSSAGraph gd,gl;TurboJSRegionNativeFunction*nd=NULL,*nl=NULL;TurboJSRegionNativeStats st={0};TurboJSIRDiagnostic d={0};TurboJSRegionValueOps ops={.guard_shape=guard_shape,.load_own_slot=load_slot,.to_i64=to_i64,.from_i64=from_i64};TurboJSRegionElementLayout l={.object_pointer_mask=UINT64_MAX,.kind_offset=offsetof(MockArray,kind),.generation_offset=offsetof(MockArray,generation),.length_offset=offsetof(MockArray,length),.element_storage_offset=offsetof(MockArray,values),.element_stride=8};TurboJSRegionValue ad[2],al[2],r=0;uint64_t t0,t1,t2;int rounds=20000,i,j;volatile uint64_t sink=0;a->kind=TURBOJS_ELEMENT_KIND_PACKED_I64;a->generation=7;a->length=1024;for(i=0;i<1024;i++)a->values[i]=(TurboJSRegionValue)(i+1);dynamic_graph(&gd);loop_graph(&gl);TurboJS_RegionNativeCompileWithElementLayout(&gd,&l,&nd,&st,&d);memset(&st,0,sizeof(st));TurboJS_RegionNativeCompileWithElementLayout(&gl,&l,&nl,&st,&d);ad[0]=(TurboJSRegionValue)(uintptr_t)a;al[0]=ad[0];al[1]=1024;t0=ns();for(i=0;i<rounds;i++){uint64_t s=0;for(j=0;j<1024;j++){ad[1]=j;TurboJS_RegionNativeInvokeValues(nd,ad,2,&ops,NULL,&r);s+=(uint64_t)r;}sink+=s;}t1=ns();for(i=0;i<rounds;i++){TurboJS_RegionNativeInvokeValues(nl,al,2,&ops,NULL,&r);sink+=(uint64_t)r;}t2=ns();printf("per_element_direct_ns=%.3f native_loop_ns=%.3f speedup=%.2fx checksum=%llu\n",(double)(t1-t0)/(rounds*1024),(double)(t2-t1)/rounds,((double)(t1-t0)/rounds)/((double)(t2-t1)/rounds),(unsigned long long)sink);TurboJS_RegionNativeFunctionDestroy(nd);TurboJS_RegionNativeFunctionDestroy(nl);TurboJS_SSAGraphDestroy(&gd);TurboJS_SSAGraphDestroy(&gl);free(a);return 0;}
